input.command:
awk -F: '
BEGIN {
    print "==== Password Hash Algorithm Report ===="
    print ""
}
NF > 0 {
    username = $1
    password = $2

    if (password == "*" || password == "!" || password == "") {
        hash_type = "LOCKED/DISABLED (no login)"
    } else if (password == "NP") {
        hash_type = "NP (no password set)"
    } else {
        # Extract the algorithm ID (second field when split by $)
        split(password, parts, "$")
        id = parts[2]

        if (id == "1") {
            hash_type = "MD5 (WEAK - deprecated)"
        } else if (id == "2a" || id == "2b" || id == "2x" || id == "2y") {
            hash_type = "Bcrypt (MODERATE)"
        } else if (id == "5") {
            hash_type = "SHA-256 (GOOD)"
        } else if (id == "6") {
            hash_type = "SHA-512 (STRONG - recommended)"
        } else {
            hash_type = "UNKNOWN (id=$" id ")"
        }
    }

    printf "%-20s | %s\n", username, hash_type
}
END {
    print ""
    print "==== Summary ===="
    print "Hash Algorithm IDs:"
    print "  $1  = MD5           (WEAK - deprecated)"
    print "  $2  = Bcrypt        (MODERATE)"
    print "  $5  = SHA-256       (GOOD)"
    print "  $6  = SHA-512       (STRONG - recommended)"
    print "  *   = Account locked/disabled"
}
' /etc/shadow
